import './Label.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import { Typography } from '../Typography';
import type { LabelProps } from './Label.types';

export const Label = forwardRef<HTMLDivElement, LabelProps>(
	({ type = 'default', assign, variant = 'outline', title, iconName, className, ...props }, ref) => {
		// Обратная совместимость, атрибут variant как в Material UI
		if (assign) {
			console.warn('В компоненте Label вместо параметра assing используйте variant, assing в будущем будет удален.');
		}

		const optionedVariant = assign || variant;

		return (
			<div
				data-testid="Label"
				{...props}
				className={classNames(
					'dsb_label',
					`dsb_label__${optionedVariant}`,
					`dsb_label__${type}`,
					iconName && 'dsb_label__with-icon',
					!title && 'dsb_label__without-title',
					className,
				)}
				ref={ref}
			>
				{iconName && <Icon className="dsb_label-icon" iconName={iconName} size="medium" />}

				{optionedVariant !== 'icon' && title && (
					<Typography className="dsb_label-title" variant="subtitle3">
						{title}
					</Typography>
				)}
			</div>
		);
	},
);
